export class VoidBazisSheet extends foundry.applications.api.HandlebarsApplicationMixin(
  foundry.applications.sheets.ActorSheetV2
) {
  static PARTS = foundry.utils.mergeObject(super.PARTS ?? {}, {
    content: { template: "systems/vacuum-of-the-void/templates/actor/bazis-sheet.hbs" }
  });

  static DEFAULT_OPTIONS = foundry.utils.mergeObject(
    super.DEFAULT_OPTIONS,
    {
      classes: ["vacuum-of-the-void", "sheet", "actor", "Bazis"],
      template: "systems/vacuum-of-the-void/templates/actor/bazis-sheet.hbs",
      width: 1000,
      height: 600,
      form: foundry.utils.mergeObject(super.DEFAULT_OPTIONS?.form ?? {}, { submitOnChange: true })
    },
    { inplace: false }
  );

  get actor() {
    return this.document;
  }

  async _prepareContext(options) {
    // A bázis lap jelenleg a jármű lappal megegyező logikát használja.
    // Egyszerűen meghívjuk a VoidJarmuSheet megfelelő logikáját, ha elérhető, különben a szülőét.
    let context = await super._prepareContext(options);
    context = context ?? {};
    context.actor = context.actor ?? this.actor;
    context.system = context.system ?? this.actor.system;
    return context;
  }
}

